     1Ôćĺ/**
     2Ôćĺ * Optimizer Routes
     3Ôćĺ *
     4Ôćĺ * REST endpoints for triggering and monitoring optimization jobs.
     5Ôćĺ * Jobs are processed asynchronously via BullMQ workers.
     6Ôćĺ *
     7Ôćĺ * Endpoints:
     8Ôćĺ * - POST /optimizer/run-assignment - Trigger train-to-route assignment optimization
     9Ôćĺ * - GET /optimizer/jobs/:jobId - Get job status and results
    10Ôćĺ * - POST /optimizer/tactical-schedule - Trigger tactical PM scheduling (12-week)
    11Ôćĺ * - POST /optimizer/strategic-plan - Trigger strategic planning (10-year)
    12Ôćĺ *
    13Ôćĺ * @see specs/005-api.md Section 5.6
    14Ôćĺ */
    15Ôćĺ
    16Ôćĺimport { Hono } from 'hono';
    17Ôćĺimport {
    18Ôćĺ  success,
    19Ôćĺ  error,
    20Ôćĺ  ErrorCodes,
    21Ôćĺ  type AppVariables,
    22Ôćĺ} from '../types';
    23Ôćĺimport { getRequestId, getRequestDuration } from '../middleware/request-context';
    24Ôćĺimport { isValidUuid } from '../../lib/schemas';
    25Ôćĺimport {
    26Ôćĺ  addJob,
    27Ôćĺ  getQueue,
    28Ôćĺ  QUEUE_NAMES,
    29Ôćĺ  type OptimizerJobData,
    30Ôćĺ  type TacticalSchedulerJobData,
    31Ôćĺ  type StrategicPlannerJobData,
    32Ôćĺ} from '../../lib/queue';
    33Ôćĺ
    34Ôćĺexport const optimizerRoutes = new Hono<{ Variables: AppVariables }>();
    35Ôćĺ
    36Ôćĺ// =============================================================================
    37Ôćĺ// Types
    38Ôćĺ// =============================================================================
    39Ôćĺ
    40Ôćĺ/**
    41Ôćĺ * Request body for POST /optimizer/run-assignment
    42Ôćĺ */
    43Ôćĺinterface RunAssignmentRequest {
    44Ôćĺ  date: string; // ISO date string (YYYY-MM-DD)
    45Ôćĺ  fleetId: string;
    46Ôćĺ  depotId?: string;
    47Ôćĺ  options?: {
    48Ôćĺ    maxSolveTimeSeconds?: number;
    49Ôćĺ    explanationVerbosity?: 'MINIMAL' | 'STANDARD' | 'DETAILED';
    50Ôćĺ  };
    51Ôćĺ  constraints?: {
    52Ôćĺ    serviceRequirements?: Record<string, number>;
    53Ôćĺ    unavailableTrains?: string[];
    54Ôćĺ    preferredAssignments?: Record<string, string>;
    55Ôćĺ  };
    56Ôćĺ}
    57Ôćĺ
    58Ôćĺ/**
    59Ôćĺ * Request body for POST /optimizer/tactical-schedule
    60Ôćĺ */
    61Ôćĺinterface TacticalScheduleRequest {
    62Ôćĺ  depotId?: string;
    63Ôćĺ  fleetId?: string;
    64Ôćĺ  trainIds?: string[];
    65Ôćĺ  horizonWeeks?: number; // Default 12
    66Ôćĺ  dryRun?: boolean;
    67Ôćĺ}
    68Ôćĺ
    69Ôćĺ/**
    70Ôćĺ * Request body for POST /optimizer/strategic-plan
    71Ôćĺ */
    72Ôćĺinterface StrategicPlanRequest {
    73Ôćĺ  horizonYears?: number; // Default 10
    74Ôćĺ  fromBaselineId?: string;
    75Ôćĺ  fleetId?: string;
    76Ôćĺ  populationSize?: number;
    77Ôćĺ  generations?: number;
    78Ôćĺ}
    79Ôćĺ
    80Ôćĺ/**
    81Ôćĺ * Optimizer job status response
    82Ôćĺ */
    83Ôćĺtype OptimizerJobStatus =
    84Ôćĺ  | 'waiting'
    85Ôćĺ  | 'active'
    86Ôćĺ  | 'completed'
    87Ôćĺ  | 'failed'
    88Ôćĺ  | 'delayed'
    89Ôćĺ  | 'unknown';
    90Ôćĺ
    91Ôćĺ// =============================================================================
    92Ôćĺ// Helper Functions
    93Ôćĺ// =============================================================================
    94Ôćĺ
    95Ôćĺ/**
    96Ôćĺ * Validate ISO date string (YYYY-MM-DD)
    97Ôćĺ */
    98Ôćĺfunction isValidDateString(date: string): boolean {
    99Ôćĺ  if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) {
   100Ôćĺ    return false;
   101Ôćĺ  }
   102Ôćĺ  const parsed = new Date(date);
   103Ôćĺ  return !isNaN(parsed.getTime());
   104Ôćĺ}
   105Ôćĺ
   106Ôćĺ/**
   107Ôćĺ * Get detailed job information including result
   108Ôćĺ */
   109Ôćĺasync function getDetailedJob(
   110Ôćĺ  queueName: typeof QUEUE_NAMES[keyof typeof QUEUE_NAMES],
   111Ôćĺ  jobId: string
   112Ôćĺ): Promise<{
   113Ôćĺ  id: string;
   114Ôćĺ  status: OptimizerJobStatus;
   115Ôćĺ  progress?: unknown;
   116Ôćĺ  result?: unknown;
   117Ôćĺ  failedReason?: string;
   118Ôćĺ  startedAt?: string;
   119Ôćĺ  completedAt?: string;
   120Ôćĺ  attemptsMade?: number;
   121Ôćĺ} | null> {
   122Ôćĺ  const queue = getQueue(queueName);
   123Ôćĺ  const job = await queue.getJob(jobId);
   124Ôćĺ
   125Ôćĺ  if (!job) return null;
   126Ôćĺ
   127Ôćĺ  const state = await job.getState();
   128Ôćĺ  const result = job.returnvalue;
   129Ôćĺ  const failedReason = job.failedReason;
   130Ôćĺ  const progress = job.progress;
   131Ôćĺ  const processedOn = job.processedOn;
   132Ôćĺ  const finishedOn = job.finishedOn;
   133Ôćĺ
   134Ôćĺ  return {
   135Ôćĺ    id: job.id!,
   136Ôćĺ    status: (state as OptimizerJobStatus) || 'unknown',
   137Ôćĺ    ...(progress !== undefined && { progress }),
   138Ôćĺ    ...(result !== undefined && { result }),
   139Ôćĺ    ...(failedReason && { failedReason }),
   140Ôćĺ    ...(processedOn && { startedAt: new Date(processedOn).toISOString() }),
   141Ôćĺ    ...(finishedOn && { completedAt: new Date(finishedOn).toISOString() }),
   142Ôćĺ    attemptsMade: job.attemptsMade,
   143Ôćĺ  };
   144Ôćĺ}
   145Ôćĺ
   146Ôćĺ/**
   147Ôćĺ * Estimate completion time based on job complexity
   148Ôćĺ */
   149Ôćĺfunction estimateCompletionSeconds(trainCount: number, routeCount: number): number {
   150Ôćĺ  // Rough estimate: base time + scaling factor
   151Ôćĺ  const baseTime = 10;
   152Ôćĺ  const scaleFactor = 0.5;
   153Ôćĺ  return Math.ceil(baseTime + (trainCount * routeCount * scaleFactor) / 1000);
   154Ôćĺ}
   155Ôćĺ
   156Ôćĺ// =============================================================================
   157Ôćĺ// Routes
   158Ôćĺ// =============================================================================
   159Ôćĺ
   160Ôćĺ/**
   161Ôćĺ * POST /optimizer/run-assignment
   162Ôćĺ *
   163Ôćĺ * Trigger run assignment optimization for a specific date and fleet.
   164Ôćĺ * The optimization is performed asynchronously and returns a job ID
   165Ôćĺ * that can be used to check status and retrieve results.
   166Ôćĺ */
   167ÔćĺoptimizerRoutes.post('/optimizer/run-assignment', async (c) => {
   168Ôćĺ  const requestId = getRequestId(c);
   169Ôćĺ
   170Ôćĺ  // Parse request body
   171Ôćĺ  let body: RunAssignmentRequest;
   172Ôćĺ  try {
   173Ôćĺ    body = await c.req.json();
   174Ôćĺ  } catch {
   175Ôćĺ    return c.json(
   176Ôćĺ      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON body', requestId),
   177Ôćĺ      400
   178Ôćĺ    );
   179Ôćĺ  }
   180Ôćĺ
   181Ôćĺ  // Validate required fields
   182Ôćĺ  if (!body.date) {
   183Ôćĺ    return c.json(
   184Ôćĺ      error(ErrorCodes.VALIDATION_ERROR, 'date is required', requestId, {
   185Ôćĺ        field: 'date',
   186Ôćĺ      }),
   187Ôćĺ      400
   188Ôćĺ    );
   189Ôćĺ  }
   190Ôćĺ
   191Ôćĺ  if (!isValidDateString(body.date)) {
   192Ôćĺ    return c.json(
   193Ôćĺ      error(
   194Ôćĺ        ErrorCodes.VALIDATION_ERROR,
   195Ôćĺ        'Invalid date format. Expected YYYY-MM-DD',
   196Ôćĺ        requestId,
   197Ôćĺ        { field: 'date', value: body.date }
   198Ôćĺ      ),
   199Ôćĺ      400
   200Ôćĺ    );
   201Ôćĺ  }
   202Ôćĺ
   203Ôćĺ  if (!body.fleetId) {
   204Ôćĺ    return c.json(
   205Ôćĺ      error(ErrorCodes.VALIDATION_ERROR, 'fleetId is required', requestId, {
   206Ôćĺ        field: 'fleetId',
   207Ôćĺ      }),
   208Ôćĺ      400
   209Ôćĺ    );
   210Ôćĺ  }
   211Ôćĺ
   212Ôćĺ  if (!isValidUuid(body.fleetId)) {
   213Ôćĺ    return c.json(
   214Ôćĺ      error(
   215Ôćĺ        ErrorCodes.VALIDATION_ERROR,
   216Ôćĺ        'Invalid fleetId format. Expected UUID',
   217Ôćĺ        requestId,
   218Ôćĺ        { field: 'fleetId', value: body.fleetId }
   219Ôćĺ      ),
   220Ôćĺ      400
   221Ôćĺ    );
   222Ôćĺ  }
   223Ôćĺ
   224Ôćĺ  // Validate options if provided
   225Ôćĺ  const maxSolveTimeSeconds = body.options?.maxSolveTimeSeconds ?? 30;
   226Ôćĺ  if (maxSolveTimeSeconds < 1 || maxSolveTimeSeconds > 300) {
   227Ôćĺ    return c.json(
   228Ôćĺ      error(
   229Ôćĺ        ErrorCodes.VALIDATION_ERROR,
   230Ôćĺ        'maxSolveTimeSeconds must be between 1 and 300',
   231Ôćĺ        requestId,
   232Ôćĺ        { field: 'options.maxSolveTimeSeconds', value: maxSolveTimeSeconds }
   233Ôćĺ      ),
   234Ôćĺ      400
   235Ôćĺ    );
   236Ôćĺ  }
   237Ôćĺ
   238Ôćĺ  const validVerbosityLevels = ['MINIMAL', 'STANDARD', 'DETAILED'];
   239Ôćĺ  const verbosity = body.options?.explanationVerbosity ?? 'STANDARD';
   240Ôćĺ  if (!validVerbosityLevels.includes(verbosity)) {
   241Ôćĺ    return c.json(
   242Ôćĺ      error(
   243Ôćĺ        ErrorCodes.VALIDATION_ERROR,
   244Ôćĺ        `explanationVerbosity must be one of: ${validVerbosityLevels.join(', ')}`,
   245Ôćĺ        requestId,
   246Ôćĺ        { field: 'options.explanationVerbosity', value: verbosity }
   247Ôćĺ      ),
   248Ôćĺ      400
   249Ôćĺ    );
   250Ôćĺ  }
   251Ôćĺ
   252Ôćĺ  // Build job data
   253Ôćĺ  const jobData: OptimizerJobData = {
   254Ôćĺ    date: body.date,
   255Ôćĺ    fleetId: body.fleetId,
   256Ôćĺ    timeoutMs: maxSolveTimeSeconds * 1000,
   257Ôćĺ    ...(body.constraints && { constraints: body.constraints }),
   258Ôćĺ  };
   259Ôćĺ
   260Ôćĺ  // Add job to queue
   261Ôćĺ  const { id: jobId } = await addJob(
   262Ôćĺ    QUEUE_NAMES.OPTIMIZER,
   263Ôćĺ    'run-assignment',
   264Ôćĺ    jobData,
   265Ôćĺ    {
   266Ôćĺ      priority: 1, // High priority for run assignments
   267Ôćĺ    }
   268Ôćĺ  );
   269Ôćĺ
   270Ôćĺ  // Estimate completion time (this would be more accurate with fleet size info)
   271Ôćĺ  const estimatedCompletionSeconds = estimateCompletionSeconds(50, 10);
   272Ôćĺ
   273Ôćĺ  return c.json(
   274Ôćĺ    success(
   275Ôćĺ      {
   276Ôćĺ        jobId,
   277Ôćĺ        status: 'QUEUED',
   278Ôćĺ        estimatedCompletionSeconds,
   279Ôćĺ      },
   280Ôćĺ      {
   281Ôćĺ        timing: { durationMs: getRequestDuration(c) },
   282Ôćĺ      }
   283Ôćĺ    ),
   284Ôćĺ    202
   285Ôćĺ  );
   286Ôćĺ});
   287Ôćĺ
   288Ôćĺ/**
   289Ôćĺ * GET /optimizer/jobs/:jobId
   290Ôćĺ *
   291Ôćĺ * Get the status and results of an optimizer job.
   292Ôćĺ */
   293ÔćĺoptimizerRoutes.get('/optimizer/jobs/:jobId', async (c) => {
   294Ôćĺ  const requestId = getRequestId(c);
   295Ôćĺ  const jobId = c.req.param('jobId');
   296Ôćĺ
   297Ôćĺ  // Try to find job in optimizer queue first
   298Ôćĺ  let job = await getDetailedJob(QUEUE_NAMES.OPTIMIZER, jobId);
   299Ôćĺ
   300Ôćĺ  // If not found, try tactical scheduler queue
   301Ôćĺ  if (!job) {
   302Ôćĺ    job = await getDetailedJob(QUEUE_NAMES.TACTICAL_SCHEDULER, jobId);
   303Ôćĺ  }
   304Ôćĺ
   305Ôćĺ  // If not found, try strategic planner queue
   306Ôćĺ  if (!job) {
   307Ôćĺ    job = await getDetailedJob(QUEUE_NAMES.STRATEGIC_PLANNER, jobId);
   308Ôćĺ  }
   309Ôćĺ
   310Ôćĺ  if (!job) {
   311Ôćĺ    return c.json(
   312Ôćĺ      error(ErrorCodes.NOT_FOUND, `Job ${jobId} not found`, requestId),
   313Ôćĺ      404
   314Ôćĺ    );
   315Ôćĺ  }
   316Ôćĺ
   317Ôćĺ  // Map internal status to API status
   318Ôćĺ  const statusMap: Record<string, string> = {
   319Ôćĺ    waiting: 'QUEUED',
   320Ôćĺ    delayed: 'QUEUED',
   321Ôćĺ    active: 'PROCESSING',
   322Ôćĺ    completed: 'COMPLETED',
   323Ôćĺ    failed: 'FAILED',
   324Ôćĺ  };
   325Ôćĺ
   326Ôćĺ  const apiStatus = statusMap[job.status] || 'UNKNOWN';
   327Ôćĺ
   328Ôćĺ  // Build response based on job status
   329Ôćĺ  interface JobResponse {
   330Ôćĺ    jobId: string;
   331Ôćĺ    status: string;
   332Ôćĺ    startedAt?: string;
   333Ôćĺ    completedAt?: string;
   334Ôćĺ    progress?: unknown;
   335Ôćĺ    result?: unknown;
   336Ôćĺ    error?: {
   337Ôćĺ      message: string;
   338Ôćĺ      attemptsMade?: number;
   339Ôćĺ    };
   340Ôćĺ  }
   341Ôćĺ
   342Ôćĺ  const response: JobResponse = {
   343Ôćĺ    jobId: job.id,
   344Ôćĺ    status: apiStatus,
   345Ôćĺ    ...(job.startedAt && { startedAt: job.startedAt }),
   346Ôćĺ    ...(job.completedAt && { completedAt: job.completedAt }),
   347Ôćĺ  };
   348Ôćĺ
   349Ôćĺ  // Include progress for active jobs
   350Ôćĺ  if (job.status === 'active' && job.progress) {
   351Ôćĺ    response.progress = job.progress;
   352Ôćĺ  }
   353Ôćĺ
   354Ôćĺ  // Include result for completed jobs
   355Ôćĺ  if (job.status === 'completed' && job.result) {
   356Ôćĺ    response.result = job.result;
   357Ôćĺ  }
   358Ôćĺ
   359Ôćĺ  // Include error for failed jobs
   360Ôćĺ  if (job.status === 'failed' && job.failedReason) {
   361Ôćĺ    response.error = {
   362Ôćĺ      message: job.failedReason,
   363Ôćĺ      attemptsMade: job.attemptsMade,
   364Ôćĺ    };
   365Ôćĺ  }
   366Ôćĺ
   367Ôćĺ  return c.json(
   368Ôćĺ    success(response, {
   369Ôćĺ      timing: { durationMs: getRequestDuration(c) },
   370Ôćĺ    })
   371Ôćĺ  );
   372Ôćĺ});
   373Ôćĺ
   374Ôćĺ/**
   375Ôćĺ * POST /optimizer/tactical-schedule
   376Ôćĺ *
   377Ôćĺ * Trigger tactical PM scheduling for a 12-week horizon.
   378Ôćĺ * Optimizes PM placement considering track availability,
   379Ôćĺ * material constraints, and man-hour capacity.
   380Ôćĺ */
   381ÔćĺoptimizerRoutes.post('/optimizer/tactical-schedule', async (c) => {
   382Ôćĺ  const requestId = getRequestId(c);
   383Ôćĺ
   384Ôćĺ  // Parse request body
   385Ôćĺ  let body: TacticalScheduleRequest;
   386Ôćĺ  try {
   387Ôćĺ    body = await c.req.json();
   388Ôćĺ  } catch {
   389Ôćĺ    body = {}; // Allow empty body for default parameters
   390Ôćĺ  }
   391Ôćĺ
   392Ôćĺ  // Validate depotId if provided
   393Ôćĺ  if (body.depotId && !isValidUuid(body.depotId)) {
   394Ôćĺ    return c.json(
   395Ôćĺ      error(
   396Ôćĺ        ErrorCodes.VALIDATION_ERROR,
   397Ôćĺ        'Invalid depotId format. Expected UUID',
   398Ôćĺ        requestId,
   399Ôćĺ        { field: 'depotId', value: body.depotId }
   400Ôćĺ      ),
   401Ôćĺ      400
   402Ôćĺ    );
   403Ôćĺ  }
   404Ôćĺ
   405Ôćĺ  // Validate fleetId if provided
   406Ôćĺ  if (body.fleetId && !isValidUuid(body.fleetId)) {
   407Ôćĺ    return c.json(
   408Ôćĺ      error(
   409Ôćĺ        ErrorCodes.VALIDATION_ERROR,
   410Ôćĺ        'Invalid fleetId format. Expected UUID',
   411Ôćĺ        requestId,
   412Ôćĺ        { field: 'fleetId', value: body.fleetId }
   413Ôćĺ      ),
   414Ôćĺ      400
   415Ôćĺ    );
   416Ôćĺ  }
   417Ôćĺ
   418Ôćĺ  // Validate trainIds if provided
   419Ôćĺ  if (body.trainIds) {
   420Ôćĺ    for (const trainId of body.trainIds) {
   421Ôćĺ      if (!isValidUuid(trainId)) {
   422Ôćĺ        return c.json(
   423Ôćĺ          error(
   424Ôćĺ            ErrorCodes.VALIDATION_ERROR,
   425Ôćĺ            'Invalid trainId format in trainIds array',
   426Ôćĺ            requestId,
   427Ôćĺ            { field: 'trainIds', invalidValue: trainId }
   428Ôćĺ          ),
   429Ôćĺ          400
   430Ôćĺ        );
   431Ôćĺ      }
   432Ôćĺ    }
   433Ôćĺ  }
   434Ôćĺ
   435Ôćĺ  // Validate horizonWeeks
   436Ôćĺ  const horizonWeeks = body.horizonWeeks ?? 12;
   437Ôćĺ  if (horizonWeeks < 1 || horizonWeeks > 52) {
   438Ôćĺ    return c.json(
   439Ôćĺ      error(
   440Ôćĺ        ErrorCodes.VALIDATION_ERROR,
   441Ôćĺ        'horizonWeeks must be between 1 and 52',
   442Ôćĺ        requestId,
   443Ôćĺ        { field: 'horizonWeeks', value: horizonWeeks }
   444Ôćĺ      ),
   445Ôćĺ      400
   446Ôćĺ    );
   447Ôćĺ  }
   448Ôćĺ
   449Ôćĺ  // Build job data
   450Ôćĺ  const jobData: TacticalSchedulerJobData = {
   451Ôćĺ    fleetId: body.fleetId,
   452Ôćĺ    trainIds: body.trainIds,
   453Ôćĺ    horizonWeeks,
   454Ôćĺ    dryRun: body.dryRun ?? false,
   455Ôćĺ  };
   456Ôćĺ
   457Ôćĺ  // Add job to queue
   458Ôćĺ  const { id: jobId } = await addJob(
   459Ôćĺ    QUEUE_NAMES.TACTICAL_SCHEDULER,
   460Ôćĺ    'tactical-schedule',
   461Ôćĺ    jobData
   462Ôćĺ  );
   463Ôćĺ
   464Ôćĺ  return c.json(
   465Ôćĺ    success(
   466Ôćĺ      {
   467Ôćĺ        jobId,
   468Ôćĺ        status: 'QUEUED',
   469Ôćĺ        horizonWeeks,
   470Ôćĺ        dryRun: body.dryRun ?? false,
   471Ôćĺ      },
   472Ôćĺ      {
   473Ôćĺ        timing: { durationMs: getRequestDuration(c) },
   474Ôćĺ      }
   475Ôćĺ    ),
   476Ôćĺ    202
   477Ôćĺ  );
   478Ôćĺ});
   479Ôćĺ
   480Ôćĺ/**
   481Ôćĺ * POST /optimizer/strategic-plan
   482Ôćĺ *
   483Ôćĺ * Trigger strategic planning for a 10-year horizon.
   484Ôćĺ * Uses genetic algorithm to optimize long-term PM scheduling
   485Ôćĺ * and resource allocation.
   486Ôćĺ */
   487ÔćĺoptimizerRoutes.post('/optimizer/strategic-plan', async (c) => {
   488Ôćĺ  const requestId = getRequestId(c);
   489Ôćĺ
   490Ôćĺ  // Parse request body
   491Ôćĺ  let body: StrategicPlanRequest;
   492Ôćĺ  try {
   493Ôćĺ    body = await c.req.json();
   494Ôćĺ  } catch {
   495Ôćĺ    body = {}; // Allow empty body for default parameters
   496Ôćĺ  }
   497Ôćĺ
   498Ôćĺ  // Validate fromBaselineId if provided
   499Ôćĺ  if (body.fromBaselineId && !isValidUuid(body.fromBaselineId)) {
   500Ôćĺ    return c.json(
   501Ôćĺ      error(
   502Ôćĺ        ErrorCodes.VALIDATION_ERROR,
   503Ôćĺ        'Invalid fromBaselineId format. Expected UUID',
   504Ôćĺ        requestId,
   505Ôćĺ        { field: 'fromBaselineId', value: body.fromBaselineId }
   506Ôćĺ      ),
   507Ôćĺ      400
   508Ôćĺ    );
   509Ôćĺ  }
   510Ôćĺ
   511Ôćĺ  // Validate fleetId if provided
   512Ôćĺ  if (body.fleetId && !isValidUuid(body.fleetId)) {
   513Ôćĺ    return c.json(
   514Ôćĺ      error(
   515Ôćĺ        ErrorCodes.VALIDATION_ERROR,
   516Ôćĺ        'Invalid fleetId format. Expected UUID',
   517Ôćĺ        requestId,
   518Ôćĺ        { field: 'fleetId', value: body.fleetId }
   519Ôćĺ      ),
   520Ôćĺ      400
