   213Ôćĺ/**
   214Ôćĺ * Maximo Sync Service for bidirectional PM synchronization
   215Ôćĺ *
   216Ôćĺ * Implements the shadow record pattern from spec 007.4.2:
   217Ôćĺ * - MMS is source of truth for scheduling
   218Ôćĺ * - Shadow records track sync state with Maximo
   219Ôćĺ * - Status-based locking prevents conflicts
   220Ôćĺ *
   221Ôćĺ * @example
   222Ôćĺ * ```typescript
   223Ôćĺ * const maximoSync = getMaximoSyncService();
   224Ôćĺ *
   225Ôćĺ * // Validate before editing a PM
   226Ôćĺ * const validation = await maximoSync.validateEdit(pmId);
   227Ôćĺ * if (!validation.valid) {
   228Ôćĺ *   throw new MaximoLockError(validation.message);
   229Ôćĺ * }
   230Ôćĺ *
   231Ôćĺ * // Create shadow record for new PM
   232Ôćĺ * await maximoSync.createShadowRecord(pmId);
   233Ôćĺ *
   234Ôćĺ * // Push changes to Maximo
   235Ôćĺ * const result = await maximoSync.pushToMaximo(pmId);
   236Ôćĺ *
   237Ôćĺ * // Pull status updates from Maximo
   238Ôćĺ * await maximoSync.pullFromMaximo();
   239Ôćĺ * ```
   240Ôćĺ */
   241Ôćĺexport class MaximoSyncService extends BaseService {
   242Ôćĺ  private readonly circuitBreaker: CircuitBreaker;
   243Ôćĺ  private lastPullTimestamp: Date | null = null;
   244Ôćĺ  private maximoClient: MaximoClient;
   245Ôćĺ  private clientInitialized = false;
   246Ôćĺ
   247Ôćĺ  constructor() {
   248Ôćĺ    super({ name: 'maximo-sync-service' });
   249Ôćĺ
   250Ôćĺ    // Initialize Maximo client
   251Ôćĺ    this.maximoClient = getMaximoClient();
   252Ôćĺ
   253Ôćĺ    // Circuit breaker for Maximo API calls
   254Ôćĺ    this.circuitBreaker = new CircuitBreaker(
   255Ôćĺ      {
   256Ôćĺ        failureThreshold: 5,
   257Ôćĺ        successThreshold: 2,
   258Ôćĺ        resetTimeoutMs: 60000, // 60 seconds in open state
   259Ôćĺ        isFailure: (error) => {
   260Ôćĺ          // Only count network/availability errors as circuit breaker failures
   261Ôćĺ          if (error instanceof MaximoConnectionError) return true;
   262Ôćĺ          if (error instanceof Error) {
   263Ôćĺ            const msg = error.message.toLowerCase();
   264Ôćĺ            return (
   265Ôćĺ              msg.includes('econnrefused') ||
   266Ôćĺ              msg.includes('etimedout') ||
   267Ôćĺ              msg.includes('econnreset') ||
   268Ôćĺ              msg.includes('503') ||
   269Ôćĺ              msg.includes('504')
   270Ôćĺ            );
   271Ôćĺ          }
   272Ôćĺ          return false;
   273Ôćĺ        },
   274Ôćĺ      },
   275Ôćĺ      'maximo-sync'
   276Ôćĺ    );
   277Ôćĺ  }
   278Ôćĺ
   279Ôćĺ  /**
   280Ôćĺ   * Ensure the Maximo client is initialized before making API calls
   281Ôćĺ   */
   282Ôćĺ  private async ensureClientInitialized(): Promise<void> {
   283Ôćĺ    if (!this.clientInitialized) {
   284Ôćĺ      await this.maximoClient.initialize();
   285Ôćĺ      this.clientInitialized = true;
   286Ôćĺ    }
   287Ôćĺ  }
   288Ôćĺ
   289Ôćĺ  // ===========================================================================
   290Ôćĺ  // Edit Validation
   291Ôćĺ  // ===========================================================================
   292Ôćĺ
   293Ôćĺ  /**
   294Ôćĺ   * Validate PM edit request against Maximo status
   295Ôćĺ   *
   296Ôćĺ   * MUST be called before any PM schedule modification.
   297Ôćĺ   * Prevents race conditions where a planner reschedules a PM that
   298Ôćĺ   * technicians are actively working on.
   299Ôćĺ   *
   300Ôćĺ   * @see specs/007-integration.md Section 7.4.6
   301Ôćĺ   */
   302Ôćĺ  async validateEdit(pmScheduleId: string): Promise<EditValidationResult> {
   303Ôćĺ    return this.traced('validateEdit', async (span) => {
   304Ôćĺ      span.setAttribute(MmsAttributes.PM_SCHEDULE_ID, pmScheduleId);
   305Ôćĺ
   306Ôćĺ      // Get PM with shadow record
   307Ôćĺ      const pm = await this.getPmWithShadow(pmScheduleId);
   308Ôćĺ
   309Ôćĺ      if (!pm) {
   310Ôćĺ        return {
   311Ôćĺ          valid: false,
   312Ôćĺ          reason: 'NOT_FOUND',
   313Ôćĺ          message: 'PM schedule not found',
   314Ôćĺ        };
   315Ôćĺ      }
   316Ôćĺ
   317Ôćĺ      // Check 1: Maximo status lock
   318Ôćĺ      if (pm.shadowRecord?.maximoData) {
   319Ôćĺ        const maximoData = pm.shadowRecord.maximoData as { status?: string };
   320Ôćĺ        const maximoStatus = maximoData.status as MaximoWoStatus | undefined;
   321Ôćĺ
   322Ôćĺ        if (maximoStatus && LOCKED_MAXIMO_STATUSES.includes(maximoStatus)) {
   323Ôćĺ          span.setAttribute('maximo.status', maximoStatus);
   324Ôćĺ          span.setAttribute('maximo.locked', true);
   325Ôćĺ
   326Ôćĺ          return {
   327Ôćĺ            valid: false,
   328Ôćĺ            reason: 'MAXIMO_STATUS_LOCK',
   329Ôćĺ            message: `Cannot modify: Work order is ${MAXIMO_STATUS_LABELS[maximoStatus]} in Maximo`,
   330Ôćĺ            maximoStatus,
   331Ôćĺ            maximoWoNum: pm.shadowRecord.maximoWoNum ?? undefined,
   332Ôćĺ            suggestion:
   333Ôćĺ              maximoStatus === 'INPRG'
   334Ôćĺ                ? 'Wait for technicians to complete work, or contact supervisor to cancel in Maximo first'
   335Ôćĺ                : 'This PM has been completed/cancelled. Create a new PM if rescheduling is needed.',
   336Ôćĺ          };
   337Ôćĺ        }
   338Ôćĺ      }
   339Ôćĺ
   340Ôćĺ      // Check 2: Pending sync conflict
   341Ôćĺ      if (pm.shadowRecord?.syncStatus === 'CONFLICT') {
   342Ôćĺ        span.setAttribute('sync.conflict', true);
   343Ôćĺ
   344Ôćĺ        return {
   345Ôćĺ          valid: false,
   346Ôćĺ          reason: 'SYNC_CONFLICT',
   347Ôćĺ          message: 'Unresolved sync conflict exists. Resolve before editing.',
   348Ôćĺ          suggestion: 'Go to Integration > Conflicts to resolve',
   349Ôćĺ        };
   350Ôćĺ      }
   351Ôćĺ
   352Ôćĺ      // Check 3: Baseline lock (if PM is locked)
   353Ôćĺ      if (pm.pmSchedule.isLocked) {
   354Ôćĺ        span.setAttribute('baseline.locked', true);
   355Ôćĺ
   356Ôćĺ        return {
   357Ôćĺ          valid: false,
   358Ôćĺ          reason: 'BASELINE_LOCK',
   359Ôćĺ          message: 'PM is locked in published baseline',
   360Ôćĺ          suggestion: 'Unlock in baseline editor or create scenario to test changes',
   361Ôćĺ        };
   362Ôćĺ      }
   363Ôćĺ
   364Ôćĺ      span.setAttribute('edit.valid', true);
   365Ôćĺ      return { valid: true };
   366Ôćĺ    });
   367Ôćĺ  }
   368Ôćĺ
   369Ôćĺ  /**
   370Ôćĺ   * Check if a PM is locked by Maximo status
   371Ôćĺ   */
   372Ôćĺ  async isMaximoLocked(pmScheduleId: string): Promise<boolean> {
   373Ôćĺ    const validation = await this.validateEdit(pmScheduleId);
   374Ôćĺ    return validation.reason === 'MAXIMO_STATUS_LOCK';
   375Ôćĺ  }
