   377Ôćĺ  // ===========================================================================
   378Ôćĺ  // Shadow Record Management
   379Ôćĺ  // ===========================================================================
   380Ôćĺ
   381Ôćĺ  /**
   382Ôćĺ   * Create a shadow record for a PM schedule
   383Ôćĺ   *
   384Ôćĺ   * Called when a new PM is scheduled or when sync is first enabled.
   385Ôćĺ   */
   386Ôćĺ  async createShadowRecord(pmScheduleId: string): Promise<MaximoShadowRecord> {
   387Ôćĺ    return this.traced('createShadowRecord', async (span) => {
   388Ôćĺ      span.setAttribute(MmsAttributes.PM_SCHEDULE_ID, pmScheduleId);
   389Ôćĺ
   390Ôćĺ      // Verify PM exists
   391Ôćĺ      const pm = await this.db.query.pmSchedule.findFirst({
   392Ôćĺ        where: eq(pmSchedule.id, pmScheduleId),
   393Ôćĺ        with: {
   394Ôćĺ          train: true,
   395Ôćĺ          pmType: true,
   396Ôćĺ        },
   397Ôćĺ      });
   398Ôćĺ
   399Ôćĺ      if (!pm) {
   400Ôćĺ        throw new NotFoundError(`PM schedule not found: ${pmScheduleId}`, {
   401Ôćĺ          entityType: 'PmSchedule',
   402Ôćĺ          entityId: pmScheduleId,
   403Ôćĺ        });
   404Ôćĺ      }
   405Ôćĺ
   406Ôćĺ      // Check if shadow record already exists
   407Ôćĺ      const existing = await this.db.query.maximoShadowRecords.findFirst({
   408Ôćĺ        where: eq(maximoShadowRecords.pmScheduleId, pmScheduleId),
   409Ôćĺ      });
   410Ôćĺ
   411Ôćĺ      if (existing) {
   412Ôćĺ        this.log.info(
   413Ôćĺ          { pmScheduleId, shadowRecordId: existing.id },
   414Ôćĺ          'Shadow record already exists'
   415Ôćĺ        );
   416Ôćĺ        return existing;
   417Ôćĺ      }
   418Ôćĺ
   419Ôćĺ      // Create MMS data snapshot
   420Ôćĺ      const mmsDataSnapshot = {
   421Ôćĺ        trainId: pm.trainId,
   422Ôćĺ        pmTypeCode: pm.pmType?.pmCode ?? 'UNKNOWN',
   423Ôćĺ        targetDate: pm.targetDate,
   424Ôćĺ        status: pm.status ?? 'SCHEDULED',
   425Ôćĺ        assignedDepotId: pm.assignedDepotId ?? undefined,
   426Ôćĺ        assignedHours: pm.assignedHours ?? undefined,
   427Ôćĺ      };
   428Ôćĺ
   429Ôćĺ      // Insert shadow record
   430Ôćĺ      const [shadowRecord] = await this.db
   431Ôćĺ        .insert(maximoShadowRecords)
   432Ôćĺ        .values({
   433Ôćĺ          pmScheduleId,
   434Ôćĺ          syncStatus: 'PENDING',
   435Ôćĺ          mmsDataSnapshot,
   436Ôćĺ          syncAttempts: 0,
   437Ôćĺ          nextSyncAt: new Date(), // Sync immediately
   438Ôćĺ        })
   439Ôćĺ        .returning();
   440Ôćĺ
   441Ôćĺ      span.setAttribute('shadow.record.id', shadowRecord.id);
   442Ôćĺ      this.log.info(
   443Ôćĺ        { pmScheduleId, shadowRecordId: shadowRecord.id },
   444Ôćĺ        'Created shadow record for PM schedule'
   445Ôćĺ      );
   446Ôćĺ
   447Ôćĺ      return shadowRecord;
   448Ôćĺ    });
   449Ôćĺ  }
