   501Ôćĺ  /**
   502Ôćĺ   * List shadow records with filters
   503Ôćĺ   */
   504Ôćĺ  async listShadowRecords(
   505Ôćĺ    filters: ShadowRecordFilters = {},
   506Ôćĺ    pagination: PaginationOptions = {}
   507Ôćĺ  ): Promise<PaginatedShadowRecords> {
   508Ôćĺ    return this.traced('listShadowRecords', async (span) => {
   509Ôćĺ      const { page = 1, pageSize = 50 } = pagination;
   510Ôćĺ      const offset = (page - 1) * pageSize;
   511Ôćĺ
   512Ôćĺ      // Build where conditions
   513Ôćĺ      const conditions: SQL<unknown>[] = [];
   514Ôćĺ
   515Ôćĺ      if (filters.syncStatus) {
   516Ôćĺ        const statuses = Array.isArray(filters.syncStatus)
   517Ôćĺ          ? filters.syncStatus
   518Ôćĺ          : [filters.syncStatus];
   519Ôćĺ        conditions.push(inArray(maximoShadowRecords.syncStatus, statuses));
   520Ôćĺ      }
   521Ôćĺ
   522Ôćĺ      if (filters.pmScheduleId) {
   523Ôćĺ        conditions.push(eq(maximoShadowRecords.pmScheduleId, filters.pmScheduleId));
   524Ôćĺ      }
   525Ôćĺ
   526Ôćĺ      if (filters.maximoWoNum) {
   527Ôćĺ        conditions.push(eq(maximoShadowRecords.maximoWoNum, filters.maximoWoNum));
   528Ôćĺ      }
   529Ôćĺ
   530Ôćĺ      if (filters.hasConflict) {
   531Ôćĺ        conditions.push(eq(maximoShadowRecords.syncStatus, 'CONFLICT'));
   532Ôćĺ      }
   533Ôćĺ
   534Ôćĺ      if (filters.needsSync) {
   535Ôćĺ        const needsSyncCondition = or(
   536Ôćĺ          eq(maximoShadowRecords.syncStatus, 'PENDING'),
   537Ôćĺ          and(
   538Ôćĺ            eq(maximoShadowRecords.syncStatus, 'ERROR'),
   539Ôćĺ            lt(maximoShadowRecords.syncAttempts, 5)
   540Ôćĺ          )
   541Ôćĺ        );
   542Ôćĺ        if (needsSyncCondition) {
   543Ôćĺ          conditions.push(needsSyncCondition);
   544Ôćĺ        }
   545Ôćĺ      }
   546Ôćĺ
   547Ôćĺ      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
   548Ôćĺ
   549Ôćĺ      // Get total count
   550Ôćĺ      const [{ value: total }] = await this.db
   551Ôćĺ        .select({ value: count() })
   552Ôćĺ        .from(maximoShadowRecords)
   553Ôćĺ        .where(whereClause);
   554Ôćĺ
   555Ôćĺ      // Get records
   556Ôćĺ      const records = await this.db.query.maximoShadowRecords.findMany({
   557Ôćĺ        where: whereClause,
   558Ôćĺ        orderBy: [desc(maximoShadowRecords.updatedAt)],
   559Ôćĺ        limit: pageSize,
   560Ôćĺ        offset,
   561Ôćĺ        with: {
   562Ôćĺ          pmScheduleEntry: {
   563Ôćĺ            with: {
   564Ôćĺ              train: true,
   565Ôćĺ              pmType: true,
   566Ôćĺ              assignedDepot: true,
   567Ôćĺ            },
   568Ôćĺ          },
   569Ôćĺ        },
   570Ôćĺ      });
   571Ôćĺ
   572Ôćĺ      // Transform to ShadowRecordWithPm
   573Ôćĺ      const data: ShadowRecordWithPm[] = records.map((r) => ({
   574Ôćĺ        shadowRecord: r,
   575Ôćĺ        pmSchedule: {
   576Ôćĺ          ...r.pmScheduleEntry,
   577Ôćĺ          train: r.pmScheduleEntry.train
   578Ôćĺ            ? {
   579Ôćĺ                id: r.pmScheduleEntry.train.id,
   580Ôćĺ                trainNumber: r.pmScheduleEntry.train.trainNumber,
   581Ôćĺ              }
   582Ôćĺ            : undefined,
