   616Ôćĺ  /**
   617Ôćĺ   * Push MMS changes to Maximo for a specific PM
   618Ôćĺ   *
   619Ôćĺ   * Creates or updates the Maximo work order based on shadow record state.
   620Ôćĺ   *
   621Ôćĺ   * @see specs/007-integration.md Section 7.4.7
   622Ôćĺ   */
   623Ôćĺ  async pushToMaximo(pmScheduleId: string): Promise<PushResult> {
   624Ôćĺ    return this.traced('pushToMaximo', async (span) => {
   625Ôćĺ      span.setAttribute(MmsAttributes.PM_SCHEDULE_ID, pmScheduleId);
   626Ôćĺ
   627Ôćĺ      const pmWithShadow = await this.getPmWithShadow(pmScheduleId);
   628Ôćĺ
   629Ôćĺ      if (!pmWithShadow) {
   630Ôćĺ        return { action: 'ERROR', error: 'PM schedule not found' };
   631Ôćĺ      }
   632Ôćĺ
   633Ôćĺ      const { pmSchedule: pm, shadowRecord } = pmWithShadow;
   634Ôćĺ
   635Ôćĺ      // Create shadow record if doesn't exist
   636Ôćĺ      let shadow = shadowRecord;
   637Ôćĺ      if (!shadow?.id) {
   638Ôćĺ        shadow = await this.createShadowRecord(pmScheduleId);
   639Ôćĺ      }
   640Ôćĺ
   641Ôćĺ      // Check circuit breaker state
   642Ôćĺ      if (this.circuitBreaker.getState() === 'OPEN') {
   643Ôćĺ        this.log.warn({ pmScheduleId }, 'Circuit breaker is open, skipping push');
   644Ôćĺ        return { action: 'SKIPPED', reason: 'Circuit breaker open' };
   645Ôćĺ      }
   646Ôćĺ
   647Ôćĺ      const syncAttempts = shadow.syncAttempts ?? 0;
   648Ôćĺ
   649Ôćĺ      try {
   650Ôćĺ        // No Maximo WO yet - create new
   651Ôćĺ        if (!shadow.maximoWoNum) {
   652Ôćĺ          // Use circuit breaker for Maximo API call
   653Ôćĺ          const woNum = await this.circuitBreaker.execute(() =>
   654Ôćĺ            this.createMaximoWorkOrder(pm)
   655Ôćĺ          );
   656Ôćĺ
   657Ôćĺ          await this.updateShadowRecord(shadow.id, {
   658Ôćĺ            maximoWoNum: woNum,
   659Ôćĺ            syncStatus: 'SYNCED',
   660Ôćĺ            lastSyncAt: new Date(),
   661Ôćĺ            lastSyncError: null,
   662Ôćĺ            syncAttempts: syncAttempts + 1,
   663Ôćĺ            mmsDataSnapshot: this.createMmsSnapshot(pm),
   664Ôćĺ          });
   665Ôćĺ
   666Ôćĺ          await this.recordSyncHistory(shadow.id, 'PUSH', {
   667Ôćĺ            previousStatus: shadow.syncStatus,
   668Ôćĺ            newStatus: 'SYNCED',
   669Ôćĺ            success: true,
   670Ôćĺ          });
   671Ôćĺ
   672Ôćĺ          span.setAttribute('maximo.wo.created', woNum);
   673Ôćĺ
   674Ôćĺ          return { action: 'CREATED', woNum };
   675Ôćĺ        }
   676Ôćĺ
   677Ôćĺ        // Check if Maximo WO is in locked state
   678Ôćĺ        const maximoWo = await this.circuitBreaker.execute(() =>
   679Ôćĺ          this.fetchMaximoWorkOrder(shadow.maximoWoNum!)
   680Ôćĺ        );
   681Ôćĺ
   682Ôćĺ        if (maximoWo && LOCKED_MAXIMO_STATUSES.includes(maximoWo.status)) {
   683Ôćĺ          return {
   684Ôćĺ            action: 'SKIPPED',
   685Ôćĺ            reason: `Work order is ${MAXIMO_STATUS_LABELS[maximoWo.status]}`,
   686Ôćĺ            woNum: shadow.maximoWoNum,
   687Ôćĺ          };
   688Ôćĺ        }
   689Ôćĺ
   690Ôćĺ        // Check for conflicts
   691Ôćĺ        if (maximoWo?.changedate && shadow.lastSyncAt) {
   692Ôćĺ          const maximoChangeDate = new Date(maximoWo.changedate);
   693Ôćĺ          if (maximoChangeDate > shadow.lastSyncAt) {
   694Ôćĺ            await this.updateShadowRecord(shadow.id, {
   695Ôćĺ              syncStatus: 'CONFLICT',
   696Ôćĺ              maximoData: {
   697Ôćĺ                status: maximoWo.status,
   698Ôćĺ                schedStart: maximoWo.schedstart,
   699Ôćĺ                schedFinish: maximoWo.schedfinish,
   700Ôćĺ                actualStart: maximoWo.actstart,
   701Ôćĺ                actualFinish: maximoWo.actfinish,
   702Ôćĺ                actualLabor: maximoWo.actlabhrs,
   703Ôćĺ                changeDate: maximoWo.changedate,
   704Ôćĺ              },
   705Ôćĺ            });
   706Ôćĺ
   707Ôćĺ            await this.recordSyncHistory(shadow.id, 'PUSH', {
   708Ôćĺ              previousStatus: shadow.syncStatus,
   709Ôćĺ              newStatus: 'CONFLICT',
   710Ôćĺ              success: false,
   711Ôćĺ              errorMessage: 'Conflict detected - Maximo changed after last sync',
   712Ôćĺ            });
   713Ôćĺ
   714Ôćĺ            return { action: 'CONFLICT', woNum: shadow.maximoWoNum };
   715Ôćĺ          }
   716Ôćĺ        }
   717Ôćĺ
   718Ôćĺ        // Update existing work order
   719Ôćĺ        await this.circuitBreaker.execute(() =>
   720Ôćĺ          this.updateMaximoWorkOrder(shadow.maximoWoNum!, pm)
   721Ôćĺ        );
   722Ôćĺ
   723Ôćĺ        await this.updateShadowRecord(shadow.id, {
   724Ôćĺ          syncStatus: 'SYNCED',
   725Ôćĺ          lastSyncAt: new Date(),
   726Ôćĺ          lastSyncError: null,
   727Ôćĺ          syncAttempts: syncAttempts + 1,
   728Ôćĺ          mmsDataSnapshot: this.createMmsSnapshot(pm),
   729Ôćĺ          pendingChanges: null,
   730Ôćĺ        });
   731Ôćĺ
   732Ôćĺ        await this.recordSyncHistory(shadow.id, 'PUSH', {
   733Ôćĺ          previousStatus: shadow.syncStatus,
   734Ôćĺ          newStatus: 'SYNCED',
   735Ôćĺ          success: true,
   736Ôćĺ        });
   737Ôćĺ
   738Ôćĺ        span.setAttribute('maximo.wo.updated', shadow.maximoWoNum);
   739Ôćĺ
   740Ôćĺ        return { action: 'UPDATED', woNum: shadow.maximoWoNum };
   741Ôćĺ      } catch (error) {
   742Ôćĺ        const errorMessage = error instanceof Error ? error.message : String(error);
   743Ôćĺ
   744Ôćĺ        await this.updateShadowRecord(shadow.id, {
   745Ôćĺ          syncStatus: 'ERROR',
   746Ôćĺ          lastSyncError: errorMessage,
   747Ôćĺ          syncAttempts: syncAttempts + 1,
   748Ôćĺ          nextSyncAt: this.calculateNextRetry(syncAttempts + 1),
   749Ôćĺ        });
   750Ôćĺ
   751Ôćĺ        await this.recordSyncHistory(shadow.id, 'PUSH', {
   752Ôćĺ          previousStatus: shadow.syncStatus,
   753Ôćĺ          newStatus: 'ERROR',
   754Ôćĺ          success: false,
   755Ôćĺ          errorMessage,
   756Ôćĺ        });
   757Ôćĺ
   758Ôćĺ        span.setAttribute('error', true);
   759Ôćĺ        span.setAttribute('error.message', errorMessage);
   760Ôćĺ
   761Ôćĺ        return { action: 'ERROR', error: errorMessage };
   762Ôćĺ      }
   763Ôćĺ    });
   764Ôćĺ  }
