   769Ôćĺ  async pushAllPending(): Promise<{ pushed: number; errors: number }> {
   770Ôćĺ    return this.traced('pushAllPending', async (span) => {
   771Ôćĺ      // Get all pending shadow records
   772Ôćĺ      const pending = await this.db.query.maximoShadowRecords.findMany({
   773Ôćĺ        where: or(
   774Ôćĺ          eq(maximoShadowRecords.syncStatus, 'PENDING'),
   775Ôćĺ          and(
   776Ôćĺ            eq(maximoShadowRecords.syncStatus, 'ERROR'),
