   778Ôćĺ            or(
   779Ôćĺ              isNull(maximoShadowRecords.nextSyncAt),
   780Ôćĺ              lt(maximoShadowRecords.nextSyncAt, new Date())
   781Ôćĺ            )
   782Ôćĺ          )
   783Ôćĺ        ),
   784Ôćĺ        limit: 100, // Process in batches
   785Ôćĺ      });
   786Ôćĺ
   787Ôćĺ      span.setAttribute('pending.count', pending.length);
   788Ôćĺ
   789Ôćĺ      let pushed = 0;
   790Ôćĺ      let errors = 0;
   791Ôćĺ
   792Ôćĺ      for (const record of pending) {
   793Ôćĺ        try {
