   802Ôćĺ          this.log.error(
   803Ôćĺ            { pmScheduleId: record.pmScheduleId, error },
   804Ôćĺ            'Failed to push to Maximo'
   805Ôćĺ          );
   806Ôćĺ        }
   807Ôćĺ      }
   808Ôćĺ
   809Ôćĺ      span.setAttribute('pushed.count', pushed);
   810Ôćĺ      span.setAttribute('errors.count', errors);
   811Ôćĺ
   812Ôćĺ      return { pushed, errors };
   813Ôćĺ    });
   814Ôćĺ  }
