   820Ôćĺ  /**
   821Ôćĺ   * Pull Maximo status changes to MMS
   822Ôćĺ   *
   823Ôćĺ   * Queries Maximo for work orders modified since last pull and updates
   824Ôćĺ   * MMS PM statuses accordingly.
   825Ôćĺ   *
   826Ôćĺ   * @see specs/007-integration.md Section 7.4.7
   827Ôćĺ   */
   828Ôćĺ  async pullFromMaximo(): Promise<PullResult> {
   829Ôćĺ    return this.traced('pullFromMaximo', async (span) => {
   830Ôćĺ      const result: PullResult = {
   831Ôćĺ        processed: 0,
   832Ôćĺ        updated: 0,
   833Ôćĺ        conflicts: 0,
