   835Ôćĺ        details: [],
   836Ôćĺ      };
   837Ôćĺ
   838Ôćĺ      // Check circuit breaker state
   839Ôćĺ      if (this.circuitBreaker.getState() === 'OPEN') {
   840Ôćĺ        this.log.warn('Circuit breaker is open, skipping pull');
   841Ôćĺ        return result;
   842Ôćĺ      }
   843Ôćĺ
   844Ôćĺ      // Get all synced shadow records
   845Ôćĺ      const syncedRecords = await this.db.query.maximoShadowRecords.findMany({
   846Ôćĺ        where: and(
   847Ôćĺ          eq(maximoShadowRecords.syncStatus, 'SYNCED'),
   848Ôćĺ          sql`${maximoShadowRecords.maximoWoNum} IS NOT NULL`
   849Ôćĺ        ),
   850Ôćĺ      });
   851Ôćĺ
   852Ôćĺ      span.setAttribute('synced.records', syncedRecords.length);
   853Ôćĺ
   854Ôćĺ      for (const record of syncedRecords) {
   855Ôćĺ        result.processed++;
   856Ôćĺ
   857Ôćĺ        try {
   858Ôćĺ          if (!record.maximoWoNum) continue;
   859Ôćĺ
   860Ôćĺ          // Use circuit breaker for Maximo API call
   861Ôćĺ          const maximoWo = await this.circuitBreaker.execute(() =>
   862Ôćĺ            this.fetchMaximoWorkOrder(record.maximoWoNum!)
   863Ôćĺ          );
   864Ôćĺ
   865Ôćĺ          if (!maximoWo) {
   866Ôćĺ            result.details.push({
   867Ôćĺ              pmScheduleId: record.pmScheduleId,
   868Ôćĺ              maximoWoNum: record.maximoWoNum,
   869Ôćĺ              action: 'SKIPPED',
   870Ôćĺ              error: 'Work order not found in Maximo',
   871Ôćĺ            });
