   875Ôćĺ          const currentMaximoData = record.maximoData as { status?: string } | null;
   876Ôćĺ          const previousStatus = currentMaximoData?.status;
   877Ôćĺ
   878Ôćĺ          // Status changed
   879Ôćĺ          if (maximoWo.status !== previousStatus) {
   880Ôćĺ            await this.handleStatusChange(record, maximoWo);
   881Ôćĺ            result.updated++;
   882Ôćĺ            result.details.push({
   883Ôćĺ              pmScheduleId: record.pmScheduleId,
   884Ôćĺ              maximoWoNum: record.maximoWoNum,
   885Ôćĺ              previousStatus,
   886Ôćĺ              newStatus: maximoWo.status,
   887Ôćĺ              action: 'UPDATED',
   888Ôćĺ            });
   889Ôćĺ          }
   890Ôćĺ
   891Ôćĺ          // Record actuals if completed
   892Ôćĺ          if (
   893Ôćĺ            (maximoWo.status === 'COMP' || maximoWo.status === 'CLOSE') &&
   894Ôćĺ            maximoWo.actlabhrs
   895Ôćĺ          ) {
   896Ôćĺ            await this.recordActuals(record.pmScheduleId, maximoWo);
   897Ôćĺ          }
   898Ôćĺ        } catch (error) {
   899Ôćĺ          result.errors++;
   900Ôćĺ          result.details.push({
   901Ôćĺ            pmScheduleId: record.pmScheduleId,
   902Ôćĺ            maximoWoNum: record.maximoWoNum ?? '',
   903Ôćĺ            action: 'ERROR',
   904Ôćĺ            error: error instanceof Error ? error.message : String(error),
   905Ôćĺ          });
   906Ôćĺ        }
   907Ôćĺ      }
   908Ôćĺ
   909Ôćĺ      this.lastPullTimestamp = new Date();
   910Ôćĺ      span.setAttribute('pull.updated', result.updated);
   911Ôćĺ      span.setAttribute('pull.errors', result.errors);
   912Ôćĺ
   913Ôćĺ      return result;
   914Ôćĺ    });
   915Ôćĺ  }
