   920Ôćĺ
   921Ôćĺ  /**
   922Ôćĺ   * Resolve sync conflict
   923Ôćĺ   *
   924Ôćĺ   * @param pmScheduleId - PM schedule ID with conflict
   925Ôćĺ   * @param resolution - Strategy: USE_MMS (force push) or USE_MAXIMO (apply Maximo data)
   926Ôćĺ   * @param userId - User resolving the conflict
   927Ôćĺ   */
   928Ôćĺ  async resolveConflict(
   929Ôćĺ    pmScheduleId: string,
   930Ôćĺ    resolution: ConflictResolution,
   931Ôćĺ    userId?: string
   932Ôćĺ  ): Promise<void> {
   933Ôćĺ    return this.traced('resolveConflict', async (span) => {
   934Ôćĺ      span.setAttribute(MmsAttributes.PM_SCHEDULE_ID, pmScheduleId);
   935Ôćĺ      span.setAttribute('resolution', resolution);
   936Ôćĺ
   937Ôćĺ      const shadow = await this.db.query.maximoShadowRecords.findFirst({
   938Ôćĺ        where: eq(maximoShadowRecords.pmScheduleId, pmScheduleId),
   939Ôćĺ      });
   940Ôćĺ
   941Ôćĺ      if (!shadow) {
   942Ôćĺ        throw new NotFoundError(`Shadow record not found for PM: ${pmScheduleId}`, {
   943Ôćĺ          entityType: 'MaximoShadowRecord',
   944Ôćĺ          entityId: pmScheduleId,
   945Ôćĺ        });
   946Ôćĺ      }
   947Ôćĺ
   948Ôćĺ      if (shadow.syncStatus !== 'CONFLICT') {
   949Ôćĺ        throw new ValidationError('Shadow record is not in conflict state');
   950Ôćĺ      }
   951Ôćĺ
   952Ôćĺ      if (!shadow.maximoWoNum) {
   953Ôćĺ        throw new ValidationError('Shadow record has no Maximo work order');
   954Ôćĺ      }
   955Ôćĺ
   956Ôćĺ      if (resolution === 'USE_MMS') {
   957Ôćĺ        // Force push MMS data to Maximo
   958Ôćĺ        const pm = await this.db.query.pmSchedule.findFirst({
   959Ôćĺ          where: eq(pmSchedule.id, pmScheduleId),
   960Ôćĺ          with: { train: true, pmType: true, assignedDepot: true },
   961Ôćĺ        });
   962Ôćĺ
   963Ôćĺ        if (!pm) {
   964Ôćĺ          throw new NotFoundError(`PM schedule not found: ${pmScheduleId}`, {
   965Ôćĺ            entityType: 'PmSchedule',
   966Ôćĺ            entityId: pmScheduleId,
   967Ôćĺ          });
   968Ôćĺ        }
   969Ôćĺ
   970Ôćĺ        await this.updateMaximoWorkOrder(shadow.maximoWoNum, pm, { force: true });
   971Ôćĺ      } else {
   972Ôćĺ        // Apply Maximo data to MMS
   973Ôćĺ        const maximoWo = await this.fetchMaximoWorkOrder(shadow.maximoWoNum);
   974Ôćĺ
   975Ôćĺ        if (!maximoWo) {
   976Ôćĺ          throw new MaximoConnectionError('Failed to fetch Maximo work order');
   977Ôćĺ        }
   978Ôćĺ
   979Ôćĺ        await this.applyMaximoDataToMms(pmScheduleId, maximoWo);
   980Ôćĺ      }
   981Ôćĺ
   982Ôćĺ      // Update shadow record
   983Ôćĺ      await this.updateShadowRecord(shadow.id, {
   984Ôćĺ        syncStatus: 'SYNCED',
   985Ôćĺ        lastSyncAt: new Date(),
   986Ôćĺ        conflictResolvedAt: new Date(),
   987Ôćĺ        conflictResolvedBy: userId ?? undefined,
   988Ôćĺ        conflictResolution: resolution,
   989Ôćĺ      });
   990Ôćĺ
   991Ôćĺ      await this.recordSyncHistory(shadow.id, 'CONFLICT_RESOLVE', {
   992Ôćĺ        previousStatus: 'CONFLICT',
   993Ôćĺ        newStatus: 'SYNCED',
   994Ôćĺ        success: true,
   995Ôćĺ      });
   996Ôćĺ
   997Ôćĺ      this.log.info(
   998Ôćĺ        { pmScheduleId, resolution, userId },
   999Ôćĺ        'Conflict resolved'
  1000Ôćĺ      );
  1001Ôćĺ    });
  1002Ôćĺ  }
