   376Ôćĺ/**
   377Ôćĺ * PATCH /pm/schedule/:id
   378Ôćĺ *
   379Ôćĺ * Update a PM schedule entry (move, reassign).
   380Ôćĺ *
   381Ôćĺ * Request body:
   382Ôćĺ * - targetDate?: New target date
   383Ôćĺ * - assignedTrackId?: New track assignment
   384Ôćĺ * - reason: Reason for change (required)
   385Ôćĺ */
   386ÔćĺpmScheduleRoutes.patch('/pm/schedule/:id', async (c) => {
   387Ôćĺ  const requestId = getRequestId(c);
   388Ôćĺ  const pmId = c.req.param('id');
   389Ôćĺ
   390Ôćĺ  if (!isValidUuid(pmId)) {
   391Ôćĺ    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   392Ôćĺ  }
   393Ôćĺ
   394Ôćĺ  const body = await c.req.json();
   395Ôćĺ
   396Ôćĺ  // Validate reason is provided
   397Ôćĺ  if (!body.reason || typeof body.reason !== 'string' || body.reason.trim().length === 0) {
   398Ôćĺ    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'reason is required for PM changes', requestId), 400);
   399Ôćĺ  }
   400Ôćĺ
   401Ôćĺ  // Validate targetDate if provided
   402Ôćĺ  if (body.targetDate && !/^\d{4}-\d{2}-\d{2}$/.test(body.targetDate)) {
   403Ôćĺ    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate must be in YYYY-MM-DD format', requestId), 400);
   404Ôćĺ  }
   405Ôćĺ
   406Ôćĺ  // Validate assignedTrackId if provided
   407Ôćĺ  if (body.assignedTrackId && !isValidUuid(body.assignedTrackId)) {
   408Ôćĺ    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'assignedTrackId must be a valid UUID', requestId), 400);
   409Ôćĺ  }
   410Ôćĺ
   411Ôćĺ  const service = getService();
   412Ôćĺ  const user = c.get('user');
   413Ôćĺ
   414Ôćĺ  // Get current PM to capture old values
   415Ôćĺ  const currentPm = await service.getPm(pmId);
   416Ôćĺ
   417Ôćĺ  // Only proceed if targetDate is being changed
   418Ôćĺ  if (!body.targetDate) {
   419Ôćĺ    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate is required for PM move', requestId), 400);
   420Ôćĺ  }
   421Ôćĺ
   422Ôćĺ  const request: MovePmRequest = {
   423Ôćĺ    pmScheduleId: pmId,
   424Ôćĺ    newTargetDate: body.targetDate,
   425Ôćĺ    newTrackId: body.assignedTrackId,
   426Ôćĺ    reason: body.reason,
   427Ôćĺ    movedBy: user?.id ?? SYSTEM_USER_ID,
   428Ôćĺ  };
   429Ôćĺ
   430Ôćĺ  const updated = await service.movePm(request);
   431Ôćĺ
   432Ôćĺ  // Calculate impact assessment
   433Ôćĺ  let manhourImpact = 0;
   434Ôćĺ  let conflictsCreated = 0;
   435Ôćĺ
   436Ôćĺ  // Calculate man-hour impact if depot is assigned
   437Ôćĺ  const depotId = updated.assignedDepotId ?? currentPm.assignedDepotId;
   438Ôćĺ  if (depotId) {
   439Ôćĺ    const estimatedHours = parseFloat(currentPm.pmType?.estimatedHours ?? '0');
   440Ôćĺ    const manHourSvc = getManHourService();
   441Ôćĺ
   442Ôćĺ    // Get old and new week utilization
   443Ôćĺ    // When PM moves, it removes hours from old week and adds to new week
   444Ôćĺ    const [oldWeekCapacity, newWeekCapacity] = await Promise.all([
   445Ôćĺ      manHourSvc.checkLaborCapacity(depotId, currentPm.targetDate, 0),
   446Ôćĺ      manHourSvc.checkLaborCapacity(depotId, updated.targetDate, estimatedHours),
   447Ôćĺ    ]);
   448Ôćĺ
   449Ôćĺ    // Impact is the change in new week's utilization
   450Ôćĺ    // Positive = increased load, Negative = decreased load
   451Ôćĺ    manhourImpact = Math.round(
   452Ôćĺ      (newWeekCapacity.utilizationPct - oldWeekCapacity.utilizationPct) * 100
   453Ôćĺ    ) / 100;
   454Ôćĺ  }
   455Ôćĺ
   456Ôćĺ  // Conflicts check: movePm already validates and throws on track conflicts
   457Ôćĺ  // If we reach here, no new conflicts were created
   458Ôćĺ  // The value 0 is correct - if there were conflicts, movePm would have thrown
   459Ôćĺ  conflictsCreated = 0;
   460Ôćĺ
   461Ôćĺ  const impactAssessment = {
   462Ôćĺ    complianceStatus: updated.targetDate >= updated.constraintStart && updated.targetDate <= updated.constraintEnd
   463Ôćĺ      ? 'WITHIN_WINDOW'
   464Ôćĺ      : 'OUTSIDE_WINDOW',
   465Ôćĺ    manhourImpact,
   466Ôćĺ    conflictsCreated,
   467Ôćĺ  };
   468Ôćĺ
   469Ôćĺ  // Broadcast PM update to all connected canvas subscribers
   470Ôćĺ  const hub = getWebSocketHub();
   471Ôćĺ  hub.broadcastPmUpdated({
   472Ôćĺ    pmId: updated.id,
   473Ôćĺ    trainId: updated.trainId,
   474Ôćĺ    trainNumber: currentPm.train?.trainNumber ?? 'Unknown',
   475Ôćĺ    changes: [
   476Ôćĺ      { field: 'targetDate', oldValue: currentPm.targetDate, newValue: updated.targetDate },
   477Ôćĺ      ...(body.assignedTrackId && body.assignedTrackId !== currentPm.assignedTrackId
   478Ôćĺ        ? [{ field: 'assignedTrackId', oldValue: currentPm.assignedTrackId, newValue: body.assignedTrackId }]
   479Ôćĺ        : []),
   480Ôćĺ    ],
   481Ôćĺ    changedBy: {
   482Ôćĺ      userId: user?.id ?? SYSTEM_USER_ID,
   483Ôćĺ      displayName: user?.email ?? 'System',
   484Ôćĺ    },
   485Ôćĺ  });
   486Ôćĺ
   487Ôćĺ  return c.json(
   488Ôćĺ    success({
   489Ôćĺ      id: updated.id,
   490Ôćĺ      targetDate: updated.targetDate,
   491Ôćĺ      previousTargetDate: currentPm.targetDate,
   492Ôćĺ      assignedTrackId: updated.assignedTrackId,
   493Ôćĺ      previousTrackId: currentPm.assignedTrackId,
   494Ôćĺ      updatedAt: updated.updatedAt,
   495Ôćĺ      updatedBy: user?.id,
   496Ôćĺ      explanation: {
   497Ôćĺ        changeType: 'DATE_CHANGED',
   498Ôćĺ        reason: body.reason,
   499Ôćĺ        impactAssessment,
   500Ôćĺ      },
   501Ôćĺ    })
   502Ôćĺ  );
   503Ôćĺ});
