   566Ôćĺ      });
   567Ôćĺ    }
   568Ôćĺ
   569Ôćĺ    if (targetDate > pm.constraintEnd) {
   570Ôćĺ      violations.push({
   571Ôćĺ        type: 'COMPLIANCE_WINDOW',
   572Ôćĺ        severity: 'ERROR',
