   574Ôćĺ      });
   575Ôćĺ    }
   576Ôćĺ
   577Ôćĺ    // 4. Check track conflict (if track is assigned)
   578Ôćĺ    if (pm.assignedTrackId) {
   579Ôćĺ      const durationDays = pm.pmType?.minTrackDays ?? 1;
   580Ôćĺ      const conflict = await service.checkTrackConflict(
   581Ôćĺ        pm.assignedTrackId,
   582Ôćĺ        targetDate,
   583Ôćĺ        durationDays,
   584Ôćĺ        pmId
   585Ôćĺ      );
   586Ôćĺ
   587Ôćĺ      if (conflict) {
   588Ôćĺ        violations.push({
   589Ôćĺ          type: 'TRACK_CONFLICT',
   590Ôćĺ          severity: 'WARNING',
   591Ôćĺ          message: `Track is occupied on ${targetDate} by another PM`,
   592Ôćĺ        });
   593Ôćĺ      }
   594Ôćĺ    }
   595Ôćĺ
   596Ôćĺ    // 5. Check material availability (if depot assigned)
   597Ôćĺ    if (pm.assignedDepotId) {
   598Ôćĺ      const materialResult = await service.checkMaterialAvailability(
   599Ôćĺ        pm.pmTypeId,
   600Ôćĺ        pm.assignedDepotId,
   601Ôćĺ        targetDate
