   606Ôćĺ          .map((v) => v.partNumber)
   607Ôćĺ          .join(', ');
   608Ôćĺ        violations.push({
   609Ôćĺ          type: 'MATERIAL',
   610Ôćĺ          severity: 'ERROR',
   611Ôćĺ          message: `Missing critical parts: ${missingParts}`,
