   617Ôćĺ          message: `${materialResult.softConstraintWarnings.length} parts may not be available`,
   618Ôćĺ        });
   619Ôćĺ      }
   620Ôćĺ    }
   621Ôćĺ
   622Ôćĺ    // 6. Check service demand (need serviceDemandService)
   623Ôćĺ    // Service demand is checked by the pm-scheduler service internally
   624Ôćĺ    // For validation, we import and use it here
