   703Ôćĺ      const sourceWeek = await manHourSvc.checkLaborCapacity(depotId, currentDate, 0);
   704Ôćĺ
   705Ôćĺ      // Get target week capacity (new date, adding the PM hours)
   706Ôćĺ      const targetWeek = await manHourSvc.checkLaborCapacity(depotId, targetDate, estimatedHours);
   707Ôćĺ
   708Ôćĺ      manhourChange = {
