   759Ôćĺ      const { baselinePmSchedule, planBaselines } = await import('../../lib/db/schema');
   760Ôćĺ
   761Ôćĺ      // Find latest published baseline
   762Ôćĺ      const latestBaseline = await db.query.planBaselines.findFirst({
   763Ôćĺ        where: eq(planBaselines.status, 'PUBLISHED'),
   764Ôćĺ        orderBy: desc(planBaselines.publishedAt),
