   787Ôćĺ      driftFromBaseline = 0;
   788Ôćĺ    }
   789Ôćĺ
   790Ôćĺ    return c.json(
   791Ôćĺ      success({
   792Ôćĺ        manhourChange,
   793Ôćĺ        costChange,
   794Ôćĺ        conflictsCreated,
   795Ôćĺ        driftFromBaseline,
   796Ôćĺ      })
   797Ôćĺ    );
   798Ôćĺ  } catch (err) {
