   378Ôćĺ/**
   379Ôćĺ * GET /export/download/:filename
   380Ôćĺ *
   381Ôćĺ * Download a generated export file.
   382Ôćĺ *
   383Ôćĺ * Path Parameters:
   384Ôćĺ * - filename: Name of the file to download
   385Ôćĺ *
   386Ôćĺ * Security:
   387Ôćĺ * - Validates filename to prevent path traversal attacks
   388Ôćĺ * - Only serves files from the configured reports directory
   389Ôćĺ *
   390Ôćĺ * @returns Binary file stream with appropriate Content-Type header
   391Ôćĺ */
   392ÔćĺexportRoutes.get('/export/download/:filename', async (c) => {
   393Ôćĺ  const requestId = getRequestId(c);
   394Ôćĺ  const filename = c.req.param('filename');
   395Ôćĺ
   396Ôćĺ  // Validate filename format - must be alphanumeric with limited special chars
   397Ôćĺ  if (!filename || !/^[a-zA-Z0-9_-]+\.(pdf|xlsx|csv)$/.test(filename)) {
   398Ôćĺ    return c.json(
   399Ôćĺ      error(ErrorCodes.VALIDATION_ERROR, 'Invalid filename format', requestId, {
   400Ôćĺ        pattern: '^[a-zA-Z0-9_-]+\\.(pdf|xlsx|csv)$',
   401Ôćĺ      }),
   402Ôćĺ      400
   403Ôćĺ    );
   404Ôćĺ  }
   405Ôćĺ
   406Ôćĺ  // Prevent path traversal
   407Ôćĺ  const safeName = path.basename(filename);
   408Ôćĺ  const filePath = path.join(REPORTS_OUTPUT_DIR, safeName);
   409Ôćĺ
   410Ôćĺ  // Verify the resolved path is within the allowed directory
   411Ôćĺ  const resolvedPath = path.resolve(filePath);
   412Ôćĺ  const resolvedDir = path.resolve(REPORTS_OUTPUT_DIR);
   413Ôćĺ  if (!resolvedPath.startsWith(resolvedDir)) {
   414Ôćĺ    return c.json(
   415Ôćĺ      error(ErrorCodes.VALIDATION_ERROR, 'Invalid filename', requestId),
   416Ôćĺ      400
   417Ôćĺ    );
   418Ôćĺ  }
   419Ôćĺ
   420Ôćĺ  try {
   421Ôćĺ    // Check if file exists
   422Ôćĺ    const stats = await fs.promises.stat(filePath);
   423Ôćĺ    if (!stats.isFile()) {
   424Ôćĺ      return c.json(
   425Ôćĺ        error(ErrorCodes.NOT_FOUND, 'File not found', requestId),
   426Ôćĺ        404
   427Ôćĺ      );
   428Ôćĺ    }
   429Ôćĺ
   430Ôćĺ    // Determine content type
   431Ôćĺ    const ext = path.extname(safeName).toLowerCase();
   432Ôćĺ    const contentType = MIME_TYPES[ext] || 'application/octet-stream';
   433Ôćĺ
   434Ôćĺ    // Read file and stream response
   435Ôćĺ    const fileBuffer = await fs.promises.readFile(filePath);
   436Ôćĺ
   437Ôćĺ    // Set headers
   438Ôćĺ    c.header('Content-Type', contentType);
   439Ôćĺ    c.header('Content-Length', stats.size.toString());
   440Ôćĺ    c.header('Content-Disposition', `attachment; filename="${safeName}"`);
   441Ôćĺ    c.header('Cache-Control', 'private, max-age=3600');
   442Ôćĺ
   443Ôćĺ    return c.body(fileBuffer);
   444Ôćĺ  } catch (err) {
   445Ôćĺ    if (err && typeof err === 'object' && 'code' in err && err.code === 'ENOENT') {
   446Ôćĺ      return c.json(
   447Ôćĺ        error(ErrorCodes.NOT_FOUND, 'File not found', requestId, { filename: safeName }),
   448Ôćĺ        404
   449Ôćĺ      );
   450Ôćĺ    }
   451Ôćĺ
   452Ôćĺ    const message = err instanceof Error ? err.message : 'Failed to download file';
   453Ôćĺ    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
   454Ôćĺ  }
   455Ôćĺ});
