   660Ôćĺ
   661Ôćĺ  const latestRunId = latestRunResult[0].projectionRunId;
   662Ôćĺ
   663Ôćĺ  const conditions = [
   664Ôćĺ    eq(manhourProjections.projectionRunId, latestRunId),
   665Ôćĺ    eq(manhourProjections.granularity, 'WEEKLY'),
