   718Ôćĺ      depotCode: string;
   719Ôćĺ      requiredHours: number;
   720Ôćĺ      availableHours: number;
   721Ôćĺ      utilizationPct: number;
   722Ôćĺ      status: 'OVERLOADED' | 'OPTIMAL' | 'UNDERUTILIZED';
   723Ôćĺ      adjustments: Array<{
   724Ôćĺ        type: string;
   725Ôćĺ        hours: number;
   726Ôćĺ        status: string;
   727Ôćĺ      }>;
   728Ôćĺ    }>;
   729Ôćĺ  }>();
   730Ôćĺ
   731Ôćĺ  for (const proj of projections) {
