   743Ôćĺ      status = 'OPTIMAL';
   744Ôćĺ    }
   745Ôćĺ
   746Ôćĺ    const adjustments = (adjustmentsByProjection.get(proj.projectionId) || []).map((a) => ({
   747Ôćĺ      type: a.adjustmentType,
